+export function truncateText(value: string, max: number): {
+  text: string;
+  truncated: boolean;
+  total: number;
+} {
+  if (value.length <= max) {
+    return { text: value, truncated: false, total: value.length };
+  }
+  return {
+    text: value.slice(0, Math.max(0, max)),
+    truncated: true,
+    total: value.length,
+  };
+}
